const body = $json.body || $json;
const ids = Array.isArray(body.job_ids) ? body.job_ids.filter(Boolean) : [];
return [{
  json: {
    job_ids: ids,
    received_count: ids.length,
    wait: body.wait === undefined ? true : !!body.wait
  }
}];

const incomingItems = $items('Normalize Input', 0, 0);
const incoming = Array.isArray(incomingItems) && incomingItems.length ? incomingItems[0].json : {};
const ids = Array.isArray(incoming.job_ids) ? incoming.job_ids : [];
return [{
  json: {
    job_ids: ids,
    wait: incoming.wait === undefined ? true : !!incoming.wait,
    settings: ($json && $json.settings) ? $json.settings : {}
  }
}];

const run = $json || {};
const rows = Array.isArray(run.results) ? run.results : [];

function preferenceBucketFor(row) {
  const observation = (row && row.evaluation && row.evaluation.observation) || row.observation || {};
  const location = observation.location || {};
  return String(location.preference_bucket || 'other').trim().toLowerCase() || 'other';
}

const alertable = rows.filter((row) => {
  if (!row || row.status !== 'completed') return false;
  const score = Number(row.fit_score ?? -1);
  const tier = Number((row.evaluation && row.evaluation.company_tier) || 0);
  const passesScore = score >= 75 || (score >= 60 && [1, 2].includes(tier));
  if (!passesScore) return false;
  const bucket = preferenceBucketFor(row);
  return bucket === 'remote' || bucket === 'twin_cities';
});

const skippedForLocation = rows.filter((row) => {
  if (!row || row.status !== 'completed') return false;
  const score = Number(row.fit_score ?? -1);
  const tier = Number((row.evaluation && row.evaluation.company_tier) || 0);
  const passesScore = score >= 75 || (score >= 60 && [1, 2].includes(tier));
  if (!passesScore) return false;
  const bucket = preferenceBucketFor(row);
  return bucket !== 'remote' && bucket !== 'twin_cities';
}).length;

const maxAlerts = 5;
const preview = alertable.slice(0, maxAlerts).map((row) => {
  const ev = row.evaluation || {};
  const observation = ev.observation || row.observation || {};
  const location = observation.location || {};
  return {
    job_id: row.job_id,
    fit_score: Number(row.fit_score ?? -1),
    title: ev.title || row.job_id || null,
    company: ev.company || null,
    url: ev.url || null,
    preference_bucket: String(location.preference_bucket || 'other'),
    location_raw: location.raw || null,
  };
});

const lines = preview.map((job, index) => {
  const title = job.title || job.job_id || 'Unknown role';
  const company = job.company || 'Unknown company';
  const score = Number(job.fit_score ?? -1);
  const bucket = job.preference_bucket || 'other';
  const location = job.location_raw ? ` | ${job.location_raw}` : '';
  const url = job.url ? `\n${job.url}` : '';
  return `${index + 1}. ${title} @ ${company} (fit ${score}, ${bucket})${location}${url}`;
});

const telegramMessage = lines.length
  ? `Recall job alert\nPreferred-location candidates: ${alertable.length}\n\n${lines.join('\n\n')}`
  : '';

return [{
  json: {
    run_id: run.run_id || null,
    status: run.status || null,
    queued: run.queued ?? null,
    evaluated: run.evaluated ?? null,
    failed: run.failed ?? null,
    result_count: rows.length,
    high_fit_count: alertable.length,
    skipped_location_count: skippedForLocation,
    notifications_sent: 0,
    notification_errors: [],
    high_fit_jobs: preview,
    telegram_message: telegramMessage,
    message: `Evaluated ${rows.length} jobs. Preferred-location candidates: ${alertable.length}. Skipped for location: ${skippedForLocation}. Notifications sent: 0.`
  }
}];

const baseItems = $items('Evaluate + Notify', 0, 0);
const base = (Array.isArray(baseItems) && baseItems.length) ? { ...baseItems[0].json } : {};
const nodeOut = $json || {};
const errors = Array.isArray(base.notification_errors) ? base.notification_errors.slice() : [];
let sent = 1;
if (nodeOut.error || nodeOut.ok === false) {
  sent = 0;
  const reason = nodeOut.description || nodeOut.message || 'telegram_send_failed';
  errors.push(`telegram_send_failed:${reason}`);
}
base.notifications_sent = sent;
base.notification_errors = errors;
base.message = `Evaluated ${Number(base.result_count || 0)} jobs. Preferred-location candidates: ${Number(base.high_fit_count || 0)}. Skipped for location: ${Number(base.skipped_location_count || 0)}. Notifications sent: ${sent}.`;
return [{ json: base }];
